    expires_at      DATETIME NOT NULL,
    created_at      DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at      DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    CONSTRAINT fk_match_req_requester FOREIGN KEY (requester_id) REFERENCES users(id),
    CONSTRAINT fk_match_req_target    FOREIGN KEY (target_id)    REFERENCES users(id),
    INDEX idx_requester_id (requester_id),
    INDEX idx_target_id (target_id),
    INDEX idx_status (status),
    INDEX idx_expires_at (expires_at),
    INDEX idx_match_type_status (match_type, status)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
```

**match_results 테이블**
```sql
CREATE TABLE match_results (
    id              BIGINT  NOT NULL AUTO_INCREMENT PRIMARY KEY,
    request_id      BIGINT  NOT NULL UNIQUE,
    user_a_id       BIGINT  NOT NULL,
    user_b_id       BIGINT  NOT NULL,
    room_id         BIGINT  COMMENT '생성된 통화방',
