    CONSTRAINT fk_match_result_user_a  FOREIGN KEY (user_a_id)  REFERENCES users(id),
    CONSTRAINT fk_match_result_user_b  FOREIGN KEY (user_b_id)  REFERENCES users(id),
    CONSTRAINT fk_match_result_room    FOREIGN KEY (room_id)     REFERENCES call_rooms(id),
